import React, { useState, useEffect } from "react";
import { Card, Descriptions, Tag, Row, Col, Statistic, Button, message, Spin, Divider, Typography, Badge, List } from "antd";
import { HeartOutlined, DatabaseOutlined, CloudServerOutlined, CheckCircleOutlined, CloseCircleOutlined, ReloadOutlined, InfoCircleOutlined } from "@ant-design/icons";
import { healthApi } from "../utils/api";

const { Title, Text } = Typography;

export default function Settings() {
  const [health, setHealth] = useState(null);
  const [loading, setLoading] = useState(false);
  const [user] = useState(() => { try { return JSON.parse(localStorage.getItem("user")); } catch(e) { return null; } });

  const checkHealth = async () => {
    setLoading(true);
    try {
      const res = await healthApi.check();
      setHealth(res.data);
      message.success("тЂЦт║иТБђТЪЦт«їТѕљ");
    } catch(e) { message.error("тЂЦт║иТБђТЪЦтц▒У┤Ц"); }
    finally { setLoading(false); }
  };

  useEffect(() => { checkHealth(); }, []);

  const StatusIcon = ({up}) => up ? <CheckCircleOutlined style={{color:"#52c41a",fontSize:20}}/> : <CloseCircleOutlined style={{color:"#ff4d4f",fontSize:20}}/>;

  return (
    <div>
      <Row gutter={24}>
        <Col span={12}>
          <Card title={<span><InfoCircleOutlined/> у│╗у╗ЪС┐АТЂ»</span>}>
            <Descriptions column={1} bordered size="small">
              <Descriptions.Item label="т╣│тЈ░тљЇуД░">С║║тиЦТЎ║УЃйУй»уАгС╗ХжфїУ»Ђт╣│тЈ░</Descriptions.Item>
              <Descriptions.Item label="уЅѕТюгтЈи">v1.0.0-SNAPSHOT</Descriptions.Item>
              <Descriptions.Item label="тљјуФ»ТАєТъХ">Spring Boot 3.2.4</Descriptions.Item>
              <Descriptions.Item label="тЅЇуФ»ТАєТъХ">React 18 + Ant Design 5</Descriptions.Item>
              <Descriptions.Item label="ТЋ░ТЇ«т║Њ">PostgreSQL 15</Descriptions.Item>
              <Descriptions.Item label="у╝ЊтГў">Redis 7</Descriptions.Item>
              <Descriptions.Item label="т»╣У▒АтГўтѓе">MinIO</Descriptions.Item>
            </Descriptions>
          </Card>
        </Col>
        <Col span={12}>
          <Card title={<span><HeartOutlined/> ТюЇтіАтЂЦт║иуіХТђЂ</span>} extra={<Button icon={<ReloadOutlined/>} onClick={checkHealth} loading={loading}>тѕиТќ░</Button>}>
            {health ? (
              <List itemLayout="horizontal" dataSource={[
                { name:"у│╗у╗ЪТђ╗уіХТђЂ", status:health.status==="UP", desc:health.status },
                { name:"ТЋ░ТЇ«т║Њ (PostgreSQL)", status:health.components?.db?.status==="UP", desc:health.components?.db?.database||"" },
                { name:"у╝ЊтГў (Redis)", status:health.components?.redis?.status==="UP", desc:"Redis 7" },
              ]} renderItem={item => (
                <List.Item>
                  <List.Item.Meta avatar={<StatusIcon up={item.status}/>}
                    title={<span>{item.name} <Tag color={item.status?"success":"error"}>{item.status?"ТГБтИИ":"т╝ѓтИИ"}</Tag></span>}
                    description={item.desc}/>
                </List.Item>
              )}/>
            ) : <Spin tip="ТБђТЪЦСИГ..."/>}
          </Card>
        </Col>
      </Row>

      {user && (
        <Card title="тйЊтЅЇућеТѕи" style={{marginTop:24}}>
          <Descriptions column={2} bordered size="small">
            <Descriptions.Item label="ућеТѕитљЇ">{user.username}</Descriptions.Item>
            <Descriptions.Item label="жѓ«у«▒">{user.email}</Descriptions.Item>
            <Descriptions.Item label="УДњУЅ▓"><Tag color="blue">{user.role}</Tag></Descriptions.Item>
            <Descriptions.Item label="уіХТђЂ"><Badge status="success" text={user.status}/></Descriptions.Item>
          </Descriptions>
        </Card>
      )}
    </div>
  );
}
